import os
import json
from flask import Flask, request, jsonify
from kafka import KafkaProducer

KAFKA_BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092")
KAFKA_CLIENT_ID = os.getenv("KAFKA_CLIENT_ID", "flexible-event-publisher")
KAFKA_API_HOST = os.getenv("KAFKA_API_HOST", "0.0.0.0")
KAFKA_API_PORT = int(os.getenv("KAFKA_API_PORT", "8080"))

app = Flask(__name__)

producer = KafkaProducer(
    bootstrap_servers=[s.strip() for s in KAFKA_BOOTSTRAP_SERVERS.split(",") if s.strip()],
    client_id=KAFKA_CLIENT_ID,
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    key_serializer=lambda v: v if v is None or isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    acks=1,
    retries=3,
    linger_ms=10,
)

@app.route("/publish", methods=["POST"])
def publish():
    topic = request.args.get("topic", default="", type=str)
    if not topic:
        return jsonify({"ok": False, "error": "Missing required query parameter: topic"}), 400

    key = request.args.get("key", default=None, type=str)

    content_type = (request.headers.get("Content-Type") or "").lower()
    if "application/json" in content_type:
        try:
            payload = request.get_json(force=True, silent=False)
        except Exception:
            return jsonify({"ok": False, "error": "Invalid JSON body"}), 400
        message = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    else:
        message = request.get_data() or b""

    try:
        future = producer.send(topic, key=key, value=message)
        record_metadata = future.get(timeout=10)
        return jsonify({
            "ok": True,
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
            "timestamp": getattr(record_metadata, "timestamp", None),
        }), 200
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/healthz", methods=["GET"])
def healthz():
    return jsonify({"ok": True}), 200

@app.teardown_appcontext
def _shutdown(_exc):
    try:
        producer.flush(timeout=2)
    except Exception:
        pass

if __name__ == "__main__":
    app.run(host=KAFKA_API_HOST, port=KAFKA_API_PORT)